-- ════════════════════════════════════════════════════════════════
-- Banco v3 (Magaly): 175 platillos. Apio eliminado, 5 bowls arreglados
-- (usan Quinoa cocida), fibra real de 4 alimentos nuevos.
-- Fotos en bucket correcto 'healthyspaceclub/PLATILLOS BANCO'. Idempotente.
-- ════════════════════════════════════════════════════════════════

-- 1) Fibra real de Magaly en los 4 alimentos nuevos (v2 los metió estimados)
update public.foods set fibra_g=3.5 where id='verduras-mixtas-hsc';
update public.foods set fibra_g=3.5 where id='cacao-nibs-hsc';
update public.foods set fibra_g=0.4 where id='galleta-de-arroz-hsc';
update public.foods set peso_neto_g=60, fibra_g=1.7 where id='quinoa-cocida-hsc';

-- 2) Catálogo único (rebuild)
drop table if exists public.alimentos_catalogo cascade;
create table public.alimentos_catalogo as
  select distinct on (alimento) alimento, kcal_100g, prot_100g, lip_100g, hc_100g, fibra_100g
  from public.foods where alimento is not null and btrim(alimento) <> '' order by alimento, id;
alter table public.alimentos_catalogo add primary key (alimento);

-- 3) Ingredientes de platillos (bucket correcto)
drop table if exists public.platillos_ingredientes cascade;
create table public.platillos_ingredientes (
  id serial primary key,
  platillo text not null, tiempo text, tipo text, banda text, sabor text,
  mult_max numeric, alimento text, nombre_visible text,
  gramos numeric, max_g numeric, rol text, seccion text, nota text,
  image_filename text, orden int,
  image_url text generated always as ('https://ltveorvqvvlyivjwxjlc.supabase.co/storage/v1/object/public/healthyspaceclub/PLATILLOS%20BANCO/'||image_filename) stored
);

create index on public.platillos_ingredientes (platillo);
alter table public.platillos_ingredientes enable row level security;
create policy "read platillos_ingredientes" on public.platillos_ingredientes for select using (true);
